<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> run_tests</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">test_path</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">:</span></span>
