<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> fix_crew</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">kickoff</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">inputs</span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">state</span><span style="color:#9399B2;">)</span></span>
